+            "Documentation=https://github.com/Dicklesworthstone/storage_ballast_helper"
+        )
+        .ok();
+        writeln!(unit, "After=local-fs.target").ok();
+        writeln!(unit, "Wants=local-fs.target").ok();
+        writeln!(unit).ok();
+
+        // -- [Service] section ---------------------------------------------
